package vector;
import java.util.Arrays;

@SuppressWarnings("unchecked")
public class Vector<T> implements SimpleList<T> {

	private T[] itemArray;
	private int size = 0;
	private static final int INITIAL_CAPACITY = 100;

	public Vector() {
		this(INITIAL_CAPACITY);  // calls the other constructor that takes an int parameter
	}

	public Vector(int capacity) {
		this.itemArray = (T[]) new Object[capacity];
		this.size = 0;
	}

	public int capacity() {
		return this.itemArray.length;
	}

	/**
	 * When the underlying array fills up, we need to somehow resize it to accommodate the
	 * Vectors's elements.
	 * Ignores the request if the requested new capacity is too small to fit the elements
	 * already in the Vectorc
	 */
	//changing vector size through new array of greater size
	public void resize(int newCapacity) {
		T[] newArr = (T[]) new Object[newCapacity];
		for (int i = 0; i < size; i++) {
			newArr[i] = itemArray[i];
		}
		itemArray = newArr;
	}
	//gettor for size
	@Override
	public int size() {
		return this.size;
	}

	//resetting vector to empty objects
	@Override
	public void clear() {
		this.size = 0;
		this.itemArray = (T[]) new Object[INITIAL_CAPACITY];
	}

	//placing items at the end
	@Override
	public void insertAtTail(T item) {
		if(size == capacity()){
			resize(size + 1);
		}
		itemArray[size] = item;
		size++;
	}

	//placing items at the start
	@Override
	public void insertAtHead(T item) {
		if(size == capacity()){
			resize(size + 1);
		}
		for (int i = size; i > 0; i--) {
			itemArray[i] = itemArray[i - 1];
		}
		itemArray[0] = item;
		size++;
	}

	//placing item at specific spot
	@Override
	public void insertAt(int index, T item) {
		if(index <= size){
			if(size == capacity()){
				resize(size + 1);
			}

			for (int i = size; i > index; i--) {
				itemArray[i] = itemArray[i - 1];
			}
			itemArray[index] = item;
			size++;
		}
	}

	//removing final item and returning it
	@Override
	public T removeAtTail() {
		// TODO: Implement this method
		T item = itemArray[size-1];
		itemArray[size -1] = null;
		size--;
		return item;

	}

	//removing first item and returning it
	@Override
	public T removeAtHead() {
		// TODO: Implement this method
		T item = itemArray[0];
		for(int i = 1; i < size; i++){
			itemArray[i -1] = itemArray[i];
		}
		itemArray[size -1] = null;
		size--;
		return item;
	}

	//looking for specific item, if successful, returns location
	@Override
	public int find(T item) {
		for(int i = 0; i < size; i++){
			if(item.equals(itemArray[i])){
				return i;
			}
		}
		return -1;
	}


	//finding item at specific point and returning it
	@Override
	public T get(int index) {
		if(index > size){
			return null;
		}
		return itemArray[index];
	}

	/*
	 * This toString() method allow you to print a nicely formatted version of your Vector. E.g.
	 *     System.out.println( myVector );
	 * It uses utility methods in the Java Arrays library.
	 */
	@Override
	//returning valuable information from string
	public String toString() {
		return Arrays.toString(Arrays.copyOfRange(this.itemArray, 0, this.size));
	}

}

